(function(){const URL_SELECTOR="a.js-compact-url",MAX_SEGMENT_LENGTH=28;function truncateMiddle(e,t){return!e||e.length<=t?e:(t=Math.floor((t-1)/2),`${e.slice(0,t)}…${e.slice(e.length-t)}`)}function normalizeHost(e){return e?e.replace(/^www\./i,""):""}function compactPath(e){if(!e||"/"===e)return"";const t=e.split("/").filter(Boolean);if(!t.length)return"";if(1===t.length)return`/${truncateMiddle(t[0],MAX_SEGMENT_LENGTH)}`;const a=truncateMiddle(t[0],16),r=truncateMiddle(t[t.length-1],MAX_SEGMENT_LENGTH);return`/${a}/…/${r}`}function parseWaybackUrl(e){const t=e.match(/^https?:\/\/web\.archive\.org\/web\/(\d{8,14})\/(https?:\/\/.+)$/i);if(!t)return null;const a=t[1],r=t[2];try{const e=new URL(r),o=normalizeHost(e.hostname),s=compactPath(e.pathname),i=`${a.slice(0,4)}-${a.slice(4,6)}-${a.slice(6,8)}`;return`Archive ${i} · ${o}${s}`}catch(e){return`Archive · ${truncateMiddle(r,64)}`}}function compactUrl(e){const t=parseWaybackUrl(e);if(t)return t;try{const a=new URL(e),r=normalizeHost(a.hostname),o=compactPath(a.pathname);return`${r}${o}`}catch(t){return truncateMiddle(e,72)}}function setCompactLabel(e){const t=e.getAttribute("href");if(!t)return;const a=compactUrl(t),r=e.querySelector(".source-url-label");r?r.textContent=a:e.textContent=a,e.setAttribute("title",t),e.setAttribute("aria-label",`Open source link: ${t}`)}function initCompactUrls(){document.querySelectorAll(URL_SELECTOR).forEach(setCompactLabel)}"loading"===document.readyState?document.addEventListener("DOMContentLoaded",initCompactUrls):initCompactUrls()})();
